// ===========================================
// Abideen.dev — Custom Components
// ===========================================

$dark-card-alt: #161616;

// ---- CSS Custom Properties (Theming) ----
:root {
    --accent-gold: #{$gold};
    --accent-gold-light: #{$gold-light};
    --accent-blue: #{$blue};
    --accent-blue-light: #{$blue-light};
    --gradient-gold: linear-gradient(135deg, #{$gold} 0%, #{$gold-light} 50%, #{$gold} 100%);
    --gradient-blue: linear-gradient(135deg, #{$blue} 0%, #{$blue-light} 100%);
    --gradient-accent: linear-gradient(135deg, #{$gold} 0%, #{$blue} 100%);
    --gradient-text: linear-gradient(135deg, #{$gold} 0%, #{$gold-light} 50%, #{$blue-light} 100%);
}

// ---- Body & Base ----
body {
    font-family: $font-family-base;
    scroll-behavior: smooth;
    overflow-x: hidden;
}

h1, h2, h3, h4, h5, h6 {
    font-family: $font-family-heading;
    font-weight: 700;
}

::selection {
    background: rgba($gold, 0.3);
    color: $gold;
}

// Scrollbar
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: $dark-bg-alt;
}

::-webkit-scrollbar-thumb {
    background: $dark-border;
    border-radius: 4px;

    &:hover {
        background: $gold;
    }
}

// ---- Gradient Text ----
.text-gradient {
    background: var(--gradient-text);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.text-gradient-gold {
    background: var(--gradient-gold);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

// ---- Accent Buttons ----
.btn-gold {
    background: var(--gradient-gold);
    color: #000;
    border: none;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        color: #000;
        box-shadow: $shadow-gold;
        transform: translateY(-2px);
    }
}

.btn-blue {
    background: var(--gradient-blue);
    color: #fff;
    border: none;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        color: #fff;
        box-shadow: $shadow-blue;
        transform: translateY(-2px);
    }
}

.btn-outline-gold {
    border: 2px solid $gold;
    color: $gold;
    background: transparent;
    font-weight: 600;
    transition: $transition-base;

    &:hover {
        background: $gold;
        color: #000;
        box-shadow: $shadow-gold;
    }
}

// ---- Loading Screen ----
.loading-screen {
    position: fixed;
    inset: 0;
    z-index: 9999;
    display: flex;
    align-items: center;
    justify-content: center;
    background: $dark-bg;
    transition: opacity 0.6s ease, visibility 0.6s ease;

    &.loaded {
        opacity: 0;
        visibility: hidden;
    }

    .loader {
        width: 60px;
        height: 60px;
        border: 4px solid $dark-border;
        border-top-color: $gold;
        border-radius: 50%;
        animation: spin 0.8s linear infinite;
    }

    .loader-text {
        margin-top: 1.5rem;
        font-family: $font-family-heading;
        font-size: 1.5rem;
        font-weight: 700;
        letter-spacing: 2px;
    }
}

// ---- Navbar ----
.navbar-custom {
    transition: $transition-slow;
    padding: 1.2rem 0;

    &.scrolled {
        padding: 0.5rem 0;
        backdrop-filter: blur(12px);
    }

    .nav-link {
        position: relative;
        font-weight: 500;
        transition: $transition-fast;
        padding: 0.5rem 1rem;

        &::after {
            content: '';
            position: absolute;
            bottom: 0;
            left: 50%;
            width: 0;
            height: 2px;
            background: var(--gradient-gold);
            transition: width 0.3s ease;
            transform: translateX(-50%);
        }

        &:hover::after,
        &.active::after {
            width: 70%;
        }
    }

    .navbar-brand {
        font-family: $font-family-heading;
        font-weight: 800;
        font-size: 1.5rem;
        letter-spacing: -0.5px;
    }
}

// ---- Hero Section ----
.hero-section {
    position: relative;
    min-height: 100vh;
    display: flex;
    align-items: center;
    overflow: hidden;

    .hero-bg-gradient {
        position: absolute;
        inset: 0;
        background: radial-gradient(circle at 20% 50%, rgba($gold, 0.08) 0%, transparent 50%),
                    radial-gradient(circle at 80% 20%, rgba($blue, 0.08) 0%, transparent 50%),
                    radial-gradient(circle at 50% 80%, rgba($gold, 0.05) 0%, transparent 50%);
    }

    .hero-particles {
        position: absolute;
        inset: 0;
        pointer-events: none;
    }

    .hero-title {
        font-size: clamp(2.5rem, 6vw, 4.5rem);
        font-weight: 800;
        line-height: 1.1;
    }

    .typing-text {
        font-family: $font-family-code;
        font-size: clamp(1.2rem, 3vw, 2rem);
        font-weight: 600;

        .cursor {
            display: inline-block;
            width: 3px;
            height: 1.2em;
            background: $gold;
            margin-left: 4px;
            animation: blink 1s step-end infinite;
            vertical-align: middle;
        }
    }

    .hero-avatar {
        width: 300px;
        height: 300px;
        border-radius: 50%;
        object-fit: cover;
        border: 4px solid transparent;
        background-image: var(--gradient-accent);
        padding: 4px;
    }

    .hero-avatar-wrapper {
        position: relative;
        display: inline-block;

        &::before {
            content: '';
            position: absolute;
            inset: -10px;
            border-radius: 50%;
            background: var(--gradient-accent);
            opacity: 0.3;
            filter: blur(20px);
            z-index: -1;
        }
    }

    .scroll-down {
        position: absolute;
        bottom: 2rem;
        left: 50%;
        transform: translateX(-50%);
        color: $gold;
        font-size: 1.5rem;

        i {
            animation: scrollDown 1.5s ease-in-out infinite;
        }
    }
}

// ---- Section Headings ----
.section-heading {
    margin-bottom: 3rem;

